mapper.select:
select cl.id, cl.student_count, cs.class_id, cl.class_name, cl.course_id, co.course_name, co.course_type, t.username, cl.create_time, cl.update_time,
cr.course_rest_time from class_student as cs left join class as cl on cs.class_id = cl.id left join course as co on cl.course_id = co.id left join teacher as t on cl.teacher_id = t.id
left join course_record as cr on cr.student_id = cs.student_id and cr.course_id = cl.course_id where cs.student_id = #{studentId}
